scripts.script:
var candleCount = 10000

// OHLC random walk: each candle opens at the previous close so the series
// reads as a continuous price, dense enough that individual candles blur into
// a band (which is exactly where the canvas renderer earns its keep).
//
// The PRNG reseeds on every call (same LCG and seed as the template's global
// Math.random override, so the initial render is unchanged). The template
// override alone is not enough here: its seed is a running stream, so the
// second generateCandles call, e.g. after toggling a control, would continue
// the stream and produce a different walk, which read as "the data changed"
// when comparing downsampling on/off.
function generateCandles(count) {
  var seed = 42
  function rnd() {
    seed = (seed * 16807) % 2147483647
    return (seed - 1) / 2147483646
  }
  var data = new Array(count)
  var t = new Date('2015-01-01T00:00:00Z').getTime()
  var step = 60 * 60 * 1000 // 1 hour
  var o = 100
  for (var i = 0; i < count; i++) {
    var h = o + rnd() * 6
    var l = o - rnd() * 6
    var c = l + rnd() * (h - l)
    data[i] = {
      x: t + i * step,
      y: [+o.toFixed(2), +h.toFixed(2), +l.toFixed(2), +c.toFixed(2)],
    }
    // reflect off a floor so the walk never drifts into negative prices
    o = c < 20 ? 40 - c : c
  }
  return data
}

var candleData = generateCandles(candleCount)

// Stateless helper shared by the vanilla, React and Vue builds. The chart-bound
// updateStats (and its lastRenderMs) live in each per-format script instead,
// since they read the live instance and per-render timing.
function domNodeCount() {
  var el = document.querySelector('#chart')
  return el ? el.getElementsByTagName('*').length : 0
}

chart.options:
chart: {
  height: 480,
  type: 'candlestick',
  renderer: 'canvas',
  rendererThreshold: 8000,
  // Above 11,000 points the raw series is aggregated to a tenth of its size
  // (each bucket keeps its open, max high, min low and last close), and every
  // zoom re-samples the visible window, so detail returns as you zoom in. The
  // 2,000 and 10,000 counts stay under the threshold and render raw.
  // rebuild() recomputes targetPoints as candleCount / 10 on every change.
  dataReducer: { enabled: true, threshold: 11000, targetPoints: 1000 },
  animations: { enabled: true },
  zoom: { enabled: true, type: 'x', autoScaleYaxis: true },
  toolbar: { autoSelected: 'zoom' },
},
title: {
  text: 'Candlestick: 10,000 candles on the canvas renderer',
  align: 'left',
},
subtitle: {
  text: 'Bodies and wicks paint to a canvas layer; axes, crosshair, zoom and the OHLC tooltip stay SVG',
  align: 'left',
},
xaxis: {
  type: 'datetime',
  labels: { datetimeUTC: false },
},
yaxis: {
  tooltip: { enabled: true },
  labels: {
    formatter: function (val) {
      return val.toFixed(0)
    },
  },
},

vanilla-js-script:
// updateStats and lastRenderMs are chart-bound, so they live here (per format)
// rather than the shared head script. candleCount, candleData, generateCandles
// and domNodeCount come from the shared head script.
var lastRenderMs = 0

function updateStats() {
  var el = document.getElementById('stats')
  if (!el || typeof chart === 'undefined') return
  var active = chart.getActiveRenderer ? chart.getActiveRenderer() : 'svg'
  var drawn =
    chart.w && chart.w.seriesData && chart.w.seriesData.series[0]
      ? chart.w.seriesData.series[0].length
      : 0
  el.innerHTML =
    'Candles: ' +
    candleCount.toLocaleString() +
    '  ·  Drawn: ' +
    drawn.toLocaleString() +
    '  ·  Active renderer: ' +
    active.toUpperCase() +
    '  ·  DOM nodes in chart: ' +
    domNodeCount().toLocaleString() +
    '  ·  Render: ' +
    (lastRenderMs > 0 ? lastRenderMs + ' ms' : 'change a control to time it') +
    ''
}

// The template starts the first render; poll one frame for the instance, then
// fill in the live metrics.
requestAnimationFrame(function poll() {
  if (chart && chart.w && chart.w.globals && chart.w.globals.series) {
    updateStats()
  } else {
    requestAnimationFrame(poll)
  }
})

function rebuild() {
  candleCount = parseInt(document.getElementById('candleCount').value, 10)
  var mode = document.getElementById('rendererMode').value
  var lttbOn = document.getElementById('lttbToggle').checked

  candleData = generateCandles(candleCount)
  options.chart.renderer = mode
  options.chart.dataReducer = {
    enabled: lttbOn,
    threshold: 11000,
    // keep a tenth of the raw candles: 50k draws 5,000, 100k draws 10,000
    targetPoints: Math.round(candleCount / 10),
  }
  options.series = [{ name: 'Price', data: candleData }]
  options.title.text =
    'Candlestick: ' +
    candleCount.toLocaleString() +
    ' candles on the ' +
    (mode === 'auto' ? 'auto-selected' : mode) +
    ' renderer'

  var t = performance.now()
  chart.destroy()
  chart = new ApexCharts(document.querySelector('#chart'), options)
  chart.render().then(function () {
    lastRenderMs = Math.round(performance.now() - t)
    updateStats()
  })
}

document.getElementById('rerender').addEventListener('click', rebuild)
document.getElementById('rendererMode').addEventListener('change', rebuild)
document.getElementById('candleCount').addEventListener('change', rebuild)
document.getElementById('lttbToggle').addEventListener('change', rebuild)
document.getElementById('resetZoom').addEventListener('click', function () {
  if (chart) chart.resetSeries(true, true)
})

react-script:
React.useEffect(() => {
  // This demo destroys and recreates the chart instance on every control change,
  // so it skips the react-apexcharts wrapper and creates the instance in #chart
  // directly, exactly like the vanilla build. candleCount, candleData,
  // generateCandles and domNodeCount live in the shared head script.
  let lastRenderMs = 0
  let chart = null
  let disposed = false

  // The vanilla build gets a mutable `options` global from the template; rebuild
  // it here from the parsed chart state (copy the sub-objects we mutate so the
  // component state is left untouched).
  const options = Object.assign({ series: state.series }, state.options)
  options.chart = Object.assign({}, state.options.chart)
  options.title = Object.assign({}, state.options.title)

  function updateStats() {
    const el = document.getElementById('stats')
    if (!el || !chart) return
    const active = chart.getActiveRenderer ? chart.getActiveRenderer() : 'svg'
    const drawn =
      chart.w && chart.w.seriesData && chart.w.seriesData.series[0]
        ? chart.w.seriesData.series[0].length
        : 0
    el.innerHTML =
      'Candles: ' +
      candleCount.toLocaleString() +
      '  ·  Drawn: ' +
      drawn.toLocaleString() +
      '  ·  Active renderer: ' +
      active.toUpperCase() +
      '  ·  DOM nodes in chart: ' +
      domNodeCount().toLocaleString() +
      '  ·  Render: ' +
      (lastRenderMs > 0 ? lastRenderMs + ' ms' : 'change a control to time it') +
      ''
  }

  function rebuild() {
    candleCount = parseInt(document.getElementById('candleCount').value, 10)
    const mode = document.getElementById('rendererMode').value
    const lttbOn = document.getElementById('lttbToggle').checked

    candleData = generateCandles(candleCount)
    options.chart.renderer = mode
    options.chart.dataReducer = {
      enabled: lttbOn,
      threshold: 11000,
      // keep a tenth of the raw candles: 50k draws 5,000, 100k draws 10,000
      targetPoints: Math.round(candleCount / 10),
    }
    options.series = [{ name: 'Price', data: candleData }]
    options.title.text =
      'Candlestick: ' +
      candleCount.toLocaleString() +
      ' candles on the ' +
      (mode === 'auto' ? 'auto-selected' : mode) +
      ' renderer'

    const t = performance.now()
    if (chart) chart.destroy()
    chart = new ApexCharts(document.querySelector('#chart'), options)
    chart.render().then(function () {
      if (disposed) return
      lastRenderMs = Math.round(performance.now() - t)
      updateStats()
    })
  }

  document.getElementById('rerender').addEventListener('click', rebuild)
  document.getElementById('rendererMode').addEventListener('change', rebuild)
  document.getElementById('candleCount').addEventListener('change', rebuild)
  document.getElementById('lttbToggle').addEventListener('change', rebuild)
  document.getElementById('resetZoom').addEventListener('click', function () {
    if (chart) chart.resetSeries(true, true)
  })

  // Initial render into #chart, then fill in the live metrics.
  chart = new ApexCharts(document.querySelector('#chart'), options)
  chart.render().then(function () {
    if (disposed) return
    updateStats()
  })

  return () => {
    disposed = true
    if (chart) chart.destroy()
  }
}, [])

vue-script:
mounted: function () {
  // This demo destroys and recreates the chart instance on every control change,
  // so it skips the vue-apexcharts wrapper and creates the instance in #chart
  // directly, exactly like the vanilla build. candleCount, candleData,
  // generateCandles and domNodeCount live in the shared head script.
  var me = this
  var lastRenderMs = 0
  var chart = null

  // The vanilla build gets a mutable `options` global from the template; rebuild
  // it here from the parsed chart state (copy the sub-objects we mutate so the
  // component data is left untouched).
  var options = Object.assign({ series: me.series }, me.chartOptions)
  options.chart = Object.assign({}, me.chartOptions.chart)
  options.title = Object.assign({}, me.chartOptions.title)

  function updateStats() {
    var el = document.getElementById('stats')
    if (!el || !chart) return
    var active = chart.getActiveRenderer ? chart.getActiveRenderer() : 'svg'
    var drawn =
      chart.w && chart.w.seriesData && chart.w.seriesData.series[0]
        ? chart.w.seriesData.series[0].length
        : 0
    el.innerHTML =
      'Candles: ' +
      candleCount.toLocaleString() +
      '  ·  Drawn: ' +
      drawn.toLocaleString() +
      '  ·  Active renderer: ' +
      active.toUpperCase() +
      '  ·  DOM nodes in chart: ' +
      domNodeCount().toLocaleString() +
      '  ·  Render: ' +
      (lastRenderMs > 0 ? lastRenderMs + ' ms' : 'change a control to time it') +
      ''
  }

  function rebuild() {
    candleCount = parseInt(document.getElementById('candleCount').value, 10)
    var mode = document.getElementById('rendererMode').value
    var lttbOn = document.getElementById('lttbToggle').checked

    candleData = generateCandles(candleCount)
    options.chart.renderer = mode
    options.chart.dataReducer = {
      enabled: lttbOn,
      threshold: 11000,
      // keep a tenth of the raw candles: 50k draws 5,000, 100k draws 10,000
      targetPoints: Math.round(candleCount / 10),
    }
    options.series = [{ name: 'Price', data: candleData }]
    options.title.text =
      'Candlestick: ' +
      candleCount.toLocaleString() +
      ' candles on the ' +
      (mode === 'auto' ? 'auto-selected' : mode) +
      ' renderer'

    var t = performance.now()
    if (chart) chart.destroy()
    chart = new ApexCharts(document.querySelector('#chart'), options)
    me.candleChart = chart
    chart.render().then(function () {
      if (me.candleDisposed) return
      lastRenderMs = Math.round(performance.now() - t)
      updateStats()
    })
  }

  document.getElementById('rerender').addEventListener('click', rebuild)
  document.getElementById('rendererMode').addEventListener('change', rebuild)
  document.getElementById('candleCount').addEventListener('change', rebuild)
  document.getElementById('lttbToggle').addEventListener('change', rebuild)
  document.getElementById('resetZoom').addEventListener('click', function () {
    if (chart) chart.resetSeries(true, true)
  })

  // Initial render into #chart, then fill in the live metrics.
  chart = new ApexCharts(document.querySelector('#chart'), options)
  me.candleChart = chart
  chart.render().then(function () {
    if (me.candleDisposed) return
    updateStats()
  })
},
beforeDestroy: function () {
  this.candleDisposed = true
  if (this.candleChart) this.candleChart.destroy()
},
